-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Wicketkeeper Agility',
    'Quick reflexes, squat endurance, and diving agility for wicketkeepers',
    'sport_specific',
    'all_levels',
    8,
    5,
    'sport_specific',
    ARRAY['Increase maximal strength', 'Progressive overload', 'Build cardiovascular endurance', 'Improve VO2 max', 'Improve athletic performance']::text[],
